CREATE TABLE IF NOT EXISTS content_assets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,key text NOT NULL,category text NOT NULL CHECK(category IN ('video','audio','image','document')),provider text CHECK(provider IN ('youtube','bunny','vimeo','wistia','file')),provider_media_id text,provider_metadata jsonb NOT NULL DEFAULT '{}'::jsonb,title text NOT NULL,poster_asset_ref text,aspect_ratio jsonb NOT NULL DEFAULT '{"type":"3:4"}'::jsonb,duration_seconds integer,captions_asset_ref text,status text NOT NULL CHECK(status IN ('placeholder','ready','disabled')),content_version text NOT NULL,source_hash text NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT content_assets_tenant_key_uq UNIQUE(tenant_id,key));
CREATE INDEX IF NOT EXISTS content_assets_tenant_idx ON content_assets(tenant_id);
CREATE TABLE IF NOT EXISTS content_publications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,program_id uuid NOT NULL REFERENCES programs(id) ON DELETE CASCADE,content_version text NOT NULL,source_hash text NOT NULL,published_at timestamptz NOT NULL DEFAULT now(),CONSTRAINT content_publications_source_uq UNIQUE(tenant_id,program_id,source_hash));
CREATE INDEX IF NOT EXISTS content_publications_tenant_program_idx ON content_publications(tenant_id,program_id);
CREATE TABLE IF NOT EXISTS sos_executions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,user_id text NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,message_text text NOT NULL,expected_response text NOT NULL,desired_outcome text NOT NULL,emotion_before integer NOT NULL CHECK(emotion_before BETWEEN 1 AND 10),emotion_after integer CHECK(emotion_after BETWEEN 1 AND 10),status text NOT NULL DEFAULT 'saved' CHECK(status IN ('saved','completed')),completed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS sos_executions_tenant_user_idx ON sos_executions(tenant_id,user_id,created_at DESC);
